INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00437', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個存活分析中，共追蹤了200名參與者，最長追蹤達10年。在追蹤期間有50人發生了 疾病事件。暴露組的風險率（hazardrate）估計為每人年0.05，未暴露組的風險率估計為每人 年0.02。請問暴露和事件之間的風險比（hazardratio）是多少？', '["0.40", "0.50", "1.00", "2.50"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00438', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一項病例對照研究中，以下那項關於對照組的選擇是正確的？', '["對照組應該是具有結果事件的個體", "對照組應該根據人口學特徵與病例組進行配對", "對照組應該從與病例組相同來源的人群中選擇", "對照組的暴露率應低於病例組"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00439', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於干擾偏差（confoundingbias）的那一個陳述是正確的？', '["干擾偏差總是導致高估暴露和結果之間的關聯", "通過統計分析來調整可以完全消除干擾偏差", "干擾偏差發生在研究樣本數過小的情況下", "干擾偏差可能扭曲了暴露和結果之間的真實關聯，然方向不拘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00440', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一項研究中，研究人員調查運動與心血管疾病風險之間的關聯，並探討這種關聯是否受年 齡的影響。他們進行了分層分析以計算不同年齡組的相對風險（relativerisk,RR）。結果如下： 年齡組1（18-35歲）：RR=0.85 年齡組2（36-50歲）：RR=1.10 年齡組3（51-65歲）：RR=1.30 關於年齡對運動和心血管疾病風險關聯的影響，可以得出下列何項結論？', '["年齡沒有調節效應", "此相關在年輕人中較強", "此相關在最年長組中較強", "這種相關在不同年齡組間效應不一致"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00441', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個多元迴歸分析中，探討年齡、性別和血壓之間的關係，發現年齡和性別的交互作用項 在統計上是顯著的。這個結果應該如何解釋？', '["無論性別如何，年齡和血壓之間存在著強烈的相關", "年齡對血壓的影響因性別而異", "性別對血壓的影響與年齡無關", "必須由交互作用項的效應大小來決定此交互作用是否可忽略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00442', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個觀察性研究中，研究人員使用傾向分數匹配（propensityscorematching）來減少干擾偏 差。關於傾向分數匹配的陳述那一個是正確的？', '["根據相似的暴露量來進行病例和對照組間的配對", "有助於估計暴露和結果變項間的因果效應", "此匹配能保證在暴露組和未暴露組之所有潛在的干擾因素達到完全的平衡", "是在隨機對照試驗中，最適合來控制干擾偏差的有效方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00443', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在將流行病學研究的結果轉化為公共衛生政策時，以下那個因素是相對重要會優先考慮的？', '["主政者的個人偏好和價值觀", "政治的可行性和可接受性", "政策的成本效益和資源配置", "研究成果的科學嚴謹性和統計顯著性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00444', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '一項研究調查吸菸與肺癌間的關聯，並探討特定基因的易感受性是否會修飾這種相關性。研 究人員計算了肺癌案例中吸菸者的可歸因於基因易感性的比例（attributableproportion,AP）。 結果如下： 低基因易感性個體中的AP：0.10 高基因易感性個體中的AP：0.30 關於基因易感性對吸菸與肺癌之關係的修飾效應，可以得出以下那個結論？', '["易感性基因並沒有修飾效應", "在低基因易感性族群間的相關性較強", "在高基因易感性族群間的相關性較強", "無法判斷基因易感性組別間對相關的影響是否一樣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00445', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下那一項適當的描述了在流行病學政策應用中的「預防原則」（precautionaryprinciple）？', '["應延遲實施政策，直到政策被證明有效時", "在存在不確定或科學證據可能不足的時候，即採取預防措施", "依賴專家意見和共識，作為政策決策的依據", "優先考慮對大多數人有益的政策，即使此情況下會有一些人受到不利的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00446', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '以下有關疾病篩檢中前導時間偏差（lead-timebias）的陳述那個是正確的？', '["前導時間偏差發生在篩檢的檢驗未能檢測出早期的疾病時", "前導時間偏差會導致對篩檢效益的高估", "前導時間偏差在基於大樣本族群的篩檢計劃中，不是一個問題", "藉由使用高度敏感的篩檢檢驗法，可以有效消除前導時間偏差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "237e460ab73e", "answer_pdf_sha1": "43eeaa357780", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
